//go:build ignore

// Command gen extracts a small semantic palette from every *curated* Chroma
// style and writes internal/theme/palettes_gen.go. The generated file contains
// only colour strings (no Chroma import), so it links into the lite build.
//
// The curated set comes from internal/chromasubset's styles.txt — the same
// manifest that decides which style XMLs get embedded. Generating from one list
// is what guarantees theme.Names() never offers a theme whose highlighter is
// missing, which used to leave 55 of 75 picker entries silently falling back to
// the minimal highlighter.
//
// Run via: go generate ./internal/theme
package main

import (
	"bytes"
	"fmt"
	"go/format"
	"os"
	"sort"
	"strings"
	"text/template"

	"github.com/alecthomas/chroma/v2"
	"github.com/alecthomas/chroma/v2/styles"

	"github.com/shellcell/exex/internal/chromasubset"
)

type pal struct {
	Style                                                                                            string
	Background, Foreground, Comment, Keyword, Type, Function, Name, String, Number, Operator, Error_ string
}

func hex(s *chroma.Style, tt chroma.TokenType) string {
	e := s.Get(tt)
	if e.Colour.IsSet() {
		return e.Colour.String()
	}
	return ""
}

func main() {
	names, err := chromasubset.StyleNames()
	if err != nil {
		fatal(err)
	}
	sort.Strings(names)

	var pals []pal
	for _, name := range names {
		s := styles.Get(name)
		// styles.Get falls back to its default style for an unknown name, so an
		// asset whose filename doesn't match Chroma's registered style name would
		// otherwise be silently replaced by that fallback.
		if s == nil || !strings.EqualFold(s.Name, name) {
			fatal(fmt.Errorf("styles.txt lists %q, but Chroma registers no style by that name (got %q)", name, styleName(s)))
		}
		bg := s.Get(chroma.Background)
		p := pal{
			Style:      name,
			Foreground: hex(s, chroma.Text),
			Comment:    hex(s, chroma.Comment),
			Keyword:    hex(s, chroma.Keyword),
			Type:       hex(s, chroma.KeywordType),
			Function:   hex(s, chroma.NameFunction),
			Name:       hex(s, chroma.Name),
			String:     hex(s, chroma.LiteralString),
			Number:     hex(s, chroma.LiteralNumber),
			Operator:   hex(s, chroma.Operator),
			Error_:     hex(s, chroma.Error),
		}
		if bg.Background.IsSet() {
			p.Background = bg.Background.String()
		}
		if p.Foreground == "" && bg.Colour.IsSet() {
			p.Foreground = bg.Colour.String()
		}
		pals = append(pals, p)
	}

	tmpl := template.Must(template.New("p").Funcs(template.FuncMap{
		"q": func(s string) string { return `"` + s + `"` },
	}).Parse(tmplText))

	var raw bytes.Buffer
	if err := tmpl.Execute(&raw, pals); err != nil {
		fatal(err)
	}
	// The template emits one long map entry per line; gofmt aligns the columns.
	// Without this the generated file fails `gofmt -l`, which the repo treats as
	// a build error.
	src, err := format.Source(raw.Bytes())
	if err != nil {
		fatal(fmt.Errorf("gofmt generated source: %w", err))
	}
	if err := os.WriteFile("palettes_gen.go", src, 0o644); err != nil {
		fatal(err)
	}
	fmt.Printf("wrote %d palettes\n", len(pals))
}

func styleName(s *chroma.Style) string {
	if s == nil {
		return "<nil>"
	}
	return s.Name
}

func fatal(err error) {
	fmt.Fprintln(os.Stderr, err)
	os.Exit(1)
}

const tmplText = `// Code generated by "go generate ./internal/theme"; DO NOT EDIT.

package theme

var palettes = map[string]Palette{
{{- range .}}
	"{{.Style}}": {Background: {{q .Background}}, Foreground: {{q .Foreground}}, Comment: {{q .Comment}}, Keyword: {{q .Keyword}}, Type: {{q .Type}}, Function: {{q .Function}}, Name: {{q .Name}}, String: {{q .String}}, Number: {{q .Number}}, Operator: {{q .Operator}}, Error: {{q .Error_}}},
{{- end}}
}
`
